// // This SR latch is designed to hold its state until the inputs change, but it will reset to 0 when both S and R are high.
module sr_latch(  
    input wire S,  
    input wire R,  
    output reg Q,  
    output reg Q_bar  
);  
    always @ (S, R) begin  
        if (S && ~R) begin  
            Q <= 1;  
            Q_bar <= 0;  
        end  
        else if (~S && R) begin  
            Q <= 0;  
            Q_bar <= 1;  
        end  
        // Invalid condition will keep the previous state  
    end  
endmodule
